def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_no_solution(nums, target):
    return len(nums) < 2 or (nums[0] + nums[1] > target and nums[-1] + nums[-2] < target)

# Example usage
if __name__ == "__main__":
    nums = [1, 2, 3, 4, 5]
    target = 9
    if check_no_solution(nums, target):
        print("No solution exists.")
    else:
        result = solve(nums, target)
        print(result)
